// Script Continued Below
//  Option 1 - Create Global Script Execution
//  Customer - Copy the Scheduled Script Execution "TaskerNumberReset" into a Global Script Execution.
//  Create a SCript Execution with all of the values of this script include in global
//  Leave this Sctript Execution Active flag off
//  Leave section between "Option 1 Begin" and "Option 1 End" uncommented to make it easier to copy and review
//  Leave Option 2 below commented out

// Scroll down to see Option 2

// ------------------------------------------------------------------------------
// ****************** Optoin 1 Begin ********************************************
var counter = new GlideRecord('sys_number_counter');
counter.addQuery('table.sys_name', 'Task Tree');
counter.addQuery('table.sys_scope.scope', 'x_153465_discovert');
counter.query();

if(counter.next() ){
	counter.setWorkflow(false);
	counter.setValue('number', 1);
	counter.update();
}
// ------------------------------------------------------------------------------
// ****************** Optoin 1 End ********************************************

// Option 2 - Script Execution in Tasker, Script Include in Global
// Leave the Scheduled Script Execution "TaskerNumberReset" in the Tasker Applicatoin.
// Create a copy of the inactive Tasker "CounterReset" Script Include in Global (set active to true).
// Create Cross-scoped permissions to give Tasker permission to run the Global "CounterReset" Script Include.
// Comment the code in Option 1 above in the "TaskerNumberReset" Script Execution or remove it altogether.
// Uncomment the code in Option 2 in "TaskerNumberReset" Script Execution

